// HMAC opcional: GHL Workflows no envían x-ghl-signature — se permite el paso.
// Solo valida si el header está presente (webhooks nativos de GHL).
const sigHeader = $input.first().headers?.['x-ghl-signature'] || '';

if (!sigHeader) {
  return $input.all();
}

const crypto  = require('crypto');
const rawBody = $input.first().binary?.data
  ? Buffer.from($input.first().binary.data, 'base64').toString('utf8')
  : JSON.stringify($input.first().json);
const secret  = $env.WEBHOOK_SECRET;
if (!secret) throw new Error('WEBHOOK_SECRET no configurado');

const receivedHex = sigHeader.startsWith('sha256=') ? sigHeader.slice(7) : sigHeader;
const receivedBuf = Buffer.from(receivedHex, 'hex');
const hmac        = crypto.createHmac('sha256', secret);
hmac.update(rawBody);
const expectedBuf = Buffer.from(hmac.digest('hex'), 'hex');
if (receivedBuf.length !== expectedBuf.length || !crypto.timingSafeEqual(receivedBuf, expectedBuf)) {
  throw new Error('HMAC: firma invalida');
}
return $input.all();

// Acepta dos formatos:
//   A) Webhook nativo GHL: pipelineStageId, locationId, contactId
//   B) GHL Workflow custom webhook: pipleline_stage (nombre), location.id, contact_id
const REGEX_GHL_ID      = /^[a-zA-Z0-9_-]{8,50}$/;
const REGEX_LOCATION_ID = /^[a-zA-Z0-9]{10,30}$/;

// Nombre de etapa → ID (para cuando GHL Workflow no envía el stageId)
const STAGE_NAME_TO_ID = {
  'Nuevo lead':      'c9fd9604-1dc8-4816-a77f-3e750603963b',
  'Lead interesado': '7bdfe336-3bd6-48bd-a251-28228b782901',
  'Calendario':      '19225629-c452-4e4f-a4ae-90ad9e6aca9b',
  'Agendó Visita':   '5f8cc1c8-1d83-4d01-9441-6a5b7a155bc1',
  'Hot':             '5749d2b6-ab1d-4205-9744-bf5e78d9ca8a',
  'Seguimiento':     '42cbfc36-1ef7-4788-a020-bf12ed1f9eb8',
  'Cierre Ganado':   '8429d63a-e58e-4c4b-bcbf-7bcffcc72c8a',
  'Cierre Perdido':  'bdc19de0-5025-4ebf-85e1-7fb5c1518d36'
};

function cleanStr(val, maxLen) {
  if (val === null || val === undefined) return null;
  const s = String(val).trim().substring(0, maxLen);
  return s.length > 0 ? s : null;
}
function validateGHLId(val) {
  if (!val) return null;
  const s = String(val).trim();
  return REGEX_GHL_ID.test(s) ? s : null;
}
function parseISODate(val) {
  if (!val) return null;
  const ts = Date.parse(String(val));
  return isNaN(ts) ? null : new Date(ts).toISOString();
}
function parseFloatSafe(val) {
  if (val === null || val === undefined || val === '') return null;
  const n = parseFloat(val);
  return isNaN(n) ? null : n;
}

const raw  = $input.first().json;
const body = raw.body || raw;

const opportunity_id = validateGHLId(body.id || body.opportunityId);
const contact_id     = validateGHLId(body.contactId || body.contact_id);

// location_id: nativo (body.locationId) o Workflow (body.location.id)
const rawLocationId = (raw.params && raw.params.location_id)
  ? raw.params.location_id
  : (body.locationId || (body.location && body.location.id) || '');
const location_id   = REGEX_LOCATION_ID.test(String(rawLocationId).trim()) ? String(rawLocationId).trim() : null;

if (!opportunity_id) throw new Error('opportunity_id invalido: ' + (body.id || body.opportunityId));
if (!contact_id)     throw new Error('contact_id invalido');
if (!location_id)    throw new Error('location_id invalido: recibido=' + rawLocationId);

// stage: nativo (pipelineStageId) o Workflow (pipleline_stage = nombre con typo)
const stage_name_raw    = cleanStr(body.stageName || body.pipleline_stage || body.pipeline_stage, 200);
const stage_id_raw      = validateGHLId(body.pipelineStageId || body.stageId);
const pipeline_stage_id = stage_id_raw || (stage_name_raw ? (STAGE_NAME_TO_ID[stage_name_raw] || null) : null);

const validStatuses = ['open', 'won', 'lost', 'abandoned'];
const status = cleanStr(body.status, 20);

const clean = {
  opportunity_id,
  contact_id,
  location_id,
  pipeline_id:         validateGHLId(body.pipelineId || body.pipeline_id),
  pipeline_name:       cleanStr(body.pipelineName || body.pipeline_name, 200),
  pipeline_stage_id,
  stage_name:          stage_name_raw,
  status:              validStatuses.includes(status) ? status : null,
  monetary_value:      parseFloatSafe(body.monetaryValue || body.monetary_value) ?? 0,
  currency:            cleanStr(body.currency, 3) || 'COP',
  assigned_to_user_id: validateGHLId(body.assignedTo || body.assigned_to_user_id),
  assigned_to_name:    cleanStr(body.assignedToName || body.owner, 200),
  custom_fields:       (body.customFields && typeof body.customFields === 'object') ? body.customFields : null,
  close_date:          parseISODate(body.closeDate),
  ghl_created_at:      parseISODate(body.dateAdded || body.createdAt || body.date_created),
  ghl_updated_at:      parseISODate(body.dateUpdated || body.updatedAt),
  synced_at:           new Date().toISOString(),
  _prev_stage_id:      validateGHLId(body.previousStageId || body.prevStageId),
  _prev_stage_name:    cleanStr(body.previousStageName || body.prevStageName, 200),
  _changed_at:         parseISODate(body.dateUpdated || body.updatedAt) || new Date().toISOString()
};

return [{ json: clean }];

const TRACKED = ['pipeline_stage_id', 'status', 'monetary_value', 'assigned_to_user_id', 'pipeline_id'];
const incoming = $('Sanitizar Oportunidad').first().json;
const existing = $input.first().json;
const now = new Date().toISOString();

if (!existing || !existing.surrogate_key) {
  return [{ json: { action: 'INSERT', stage_changed: true, prev_stage_id: null, prev_stage_name: null, record: Object.assign({}, incoming, { valid_from: now, valid_to: null, is_current: true, change_reason: 'initial_insert' }) } }];
}

const changedFields = TRACKED.filter(f => String(existing[f] ?? null) !== String(incoming[f] ?? null));
const stageChanged  = changedFields.includes('pipeline_stage_id');

if (changedFields.length > 0) {
  return [{ json: {
    action:          'SCD_UPDATE',
    close_surrogate: existing.surrogate_key,
    close_valid_to:  now,
    stage_changed:   stageChanged,
    prev_stage_id:   existing.pipeline_stage_id,
    prev_stage_name: existing.stage_name,
    record:          Object.assign({}, incoming, { valid_from: now, valid_to: null, is_current: true, change_reason: changedFields.map(f => f + '_change').join(', ') })
  } }];
}

return [{ json: { action: 'UPDATE_MINOR', stage_changed: false, surrogate_key: existing.surrogate_key, synced_at: now, ghl_updated_at: incoming.ghl_updated_at || now, custom_fields: incoming.custom_fields } }];

