// Obtiene la oportunidad desde GHL para leer custom fields actuales (fechas por etapa).
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const { opportunity_id } = $('Sanitizar Oportunidad').first().json;
const apiKey = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

let resp, data;
for (let i = 0; i < 4; i++) {
  resp = await fetch(`https://services.leadconnectorhq.com/opportunities/${opportunity_id}`, {
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Version': '2021-07-28'
    }
  });
  if (resp.status === 429) { await sleep(Math.pow(2, i) * 1000); continue; }
  if (!resp.ok) throw new Error(`GET opportunity ${opportunity_id} -> HTTP ${resp.status}`);
  data = await resp.json();
  break;
}

const opp = data.opportunity || data;
return [{ json: { opp } }];

// Determina qué custom fields DATE actualizar según la etapa nueva.
// Cierra etapas abiertas (entrada sin salida), abre la nueva si no tiene fecha_entrada.

const { opp } = $input.first().json;
const { pipeline_stage_id: newStageId, opportunity_id: opportunityId } = $('Sanitizar Oportunidad').first().json;

const STAGE_MAP = {
  'c9fd9604-1dc8-4816-a77f-3e750603963b': { entradaId: 'aWaEuecxy4bmAqPvVqNJ', salidaId: 'MFMADsY77fpRy7myNODq' },
  '7bdfe336-3bd6-48bd-a251-28228b782901': { entradaId: 'tcrI9JZqMnPxMh28vFfV', salidaId: 'TuzceQVUoZlU97HLaU2p' },
  '19225629-c452-4e4f-a4ae-90ad9e6aca9b': { entradaId: '3BbTXzm8zrYlGFrnBdB6', salidaId: 'Voof1iCLXQDqVGPhkww7' },
  '5f8cc1c8-1d83-4d01-9441-6a5b7a155bc1': { entradaId: 'GYEc6JI3we2JSCxrM3kc', salidaId: 'be4qNCxjt25ghFs7axR6' },
  '5749d2b6-ab1d-4205-9744-bf5e78d9ca8a': { entradaId: '0OeRKKkytLYf2vlXchbL', salidaId: 'Zne1flxBbYLa8gIyF1zf' },
  '42cbfc36-1ef7-4788-a020-bf12ed1f9eb8': { entradaId: '2JouertsEonbaIyANlr1', salidaId: 'VtepsKumEVQpj8gNcpFe' },
  '8429d63a-e58e-4c4b-bcbf-7bcffcc72c8a': { entradaId: 'EMQNXKc41d60L9Om1zuV', salidaId: 'w1tIloODf1Bf2W59zsCh' },
  'bdc19de0-5025-4ebf-85e1-7fb5c1518d36': { entradaId: 'txHk9M6z4b65FJGWwm34', salidaId: 'eXNeJSvXSyCZRs9ZkeFS' }
};

if (!newStageId || !STAGE_MAP[newStageId]) {
  return [{ json: { opportunityId, newStageId, updates: [], hasUpdates: false } }];
}

const today = new Date().toISOString().split('T')[0];

const fieldValues = {};
for (const cf of (opp.customFields || [])) {
  if (cf.id) fieldValues[cf.id] = cf.field_value || cf.value || null;
}

const updates = [];

for (const [stageId, stage] of Object.entries(STAGE_MAP)) {
  if (stageId === newStageId) continue;
  if (fieldValues[stage.entradaId] && !fieldValues[stage.salidaId]) {
    updates.push({ id: stage.salidaId, field_value: today });
  }
}

const newStage = STAGE_MAP[newStageId];
if (!fieldValues[newStage.entradaId]) {
  updates.push({ id: newStage.entradaId, field_value: today });
}

return [{ json: { opportunityId, newStageId, updates, hasUpdates: updates.length > 0 } }];

// Escribe las fechas de entrada/salida de etapa en los custom fields de GHL.
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const { opportunityId, updates } = $input.first().json;
const apiKey = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

const body = JSON.stringify({ customFields: updates });

let resp;
for (let i = 0; i < 4; i++) {
  resp = await fetch(`https://services.leadconnectorhq.com/opportunities/${opportunityId}`, {
    method: 'PUT',
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Version': '2021-07-28',
      'Content-Type': 'application/json'
    },
    body
  });
  if (resp.status === 429) { await sleep(Math.pow(2, i) * 1000); continue; }
  if (!resp.ok) {
    const err = await resp.text();
    throw new Error(`PUT opportunity ${opportunityId} -> HTTP ${resp.status}: ${err}`);
  }
  break;
}

return [{ json: { opportunityId, updatedFields: updates.length, success: true } }];
